async function* simpleAsyncGenerator() {
  const items = [10, 20, 30];
  for (const item of items) {
    await new Promise(resolve => setTimeout(resolve, 1000)); // Simulate wait
    yield item;
  }
}

async function run() {
  for await (const num of simpleAsyncGenerator()) {
    console.log(num); // Logs 10, then 20, then 30 with 1s delay
  }
}

run();

async function* fetchDataChunks(url) {
  const response = await fetch(url);
  const reader = response.body.getReader();

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    yield value; // Yield each chunk
  }
}

async function processData() {
  for await (const chunk of fetchDataChunks('https://example.com/data')) {
    console.log(`Received chunk with length: ${chunk.length}`);
    // Process chunk here
  }
}

processData();

async function* pollApi(url, intervalMs) {
  while (true) {
    const response = await fetch(url);
    const data = await response.json();
    yield data;
    await new Promise(resolve => setTimeout(resolve, intervalMs));
  }
}

async function runPoll() {
  let counter = 0;
  for await (const update of pollApi('https://api.example.com/updates', 3000)) {
    console.log('Update received:', update);
    counter++;
    if (counter === 5) break; // Stop after 5 updates
  }
}

runPoll();

const asyncIterable = {
  async *[Symbol.asyncIterator]() {
    for (let i = 0; i < 3; i++) {
      await new Promise(res => setTimeout(res, 500));
      yield i;
    }
  }
};

(async () => {
  for await (const val of asyncIterable) {
    console.log(val); // Logs 0, then 1, then 2 every 0.5 seconds
  }
})();

